# ── Bandwidth throttle ─────────────────────────────────────────────────────
# 0 = unlimited. Set via GUI slider or --bandwidth CLI flag (KB/s).
import time as _time
import threading as _threading
_bandwidth_limit_kbps: float = 0.0
_bw_lock = _threading.Lock()
_bw_last_time: float = 0.0
_bw_bytes_this_window: int = 0

# Speed tracking callback — GUI sets this to record bytes for the speed graph
_gui_speed_cb: Optional[Any] = None   # fn(bytes_downloaded: int) → None

def _throttle_bandwidth(bytes_downloaded: int, *, record_gui: bool = True) -> None:
    """Sleep if necessary to keep download rate ≤ the configured limit.

    ``record_gui`` remains True for all legacy callers. Streaming helpers that
    publish absolute ``file_progress`` events can disable the legacy byte
    callback to avoid counting the same bytes twice.
    """
    global _bw_last_time, _bw_bytes_this_window
    # Record speed for the legacy GUI callback unless the caller already emits
    # an explicit progress event for the same bytes.
    if record_gui and _gui_speed_cb is not None:
        try:
            _gui_speed_cb(bytes_downloaded)
        except Exception as _ignored_exc:
            logger.debug("Ignored recoverable exception in _throttle_bandwidth: %s", _ignored_exc)
    limit = _bandwidth_limit_kbps
    if limit <= 0:
        return
    limit_bps = limit * 1024
    with _bw_lock:
        now = _time.monotonic()
        if _bw_last_time == 0.0:
            _bw_last_time = now
        elapsed = now - _bw_last_time
        _bw_bytes_this_window += bytes_downloaded
        expected_time = _bw_bytes_this_window / limit_bps
        sleep_for = expected_time - elapsed
        if sleep_for > 0:
            _cancel_aware_sleep(sleep_for)
            _bw_last_time = _time.monotonic()
            _bw_bytes_this_window = 0
        elif elapsed > 1.0:
            # Reset window every second
            _bw_last_time = now
            _bw_bytes_this_window = 0

