def _load_settings() -> Dict[str, Any]:
    try:
        if os.path.exists(_SETTINGS_FILE):
            with open(_SETTINGS_FILE, encoding="utf-8") as f:
                data = json.load(f)
            merged = {**_SETTINGS_DEFAULTS, **data}
            # Migration: old versions stored Anthropic keys directly in settings.json.
            # Preserve old behavior only when an old key exists and no explicit storage mode was saved.
            if data.get("ai_api_key") and "ai_key_storage" not in data:
                merged["ai_key_storage"] = "plain"
            return merged
    except Exception as e:
        # v7.5.6 fix: a corrupt settings.json used to be silently replaced by
        # defaults with no trace. Now we warn and keep a .corrupt backup so
        # the user can recover API endpoints / paths they had configured.
        logger.warning(f"settings.json unreadable ({e}) — using defaults; "
                       f"backup saved as settings.json.corrupt")
        try:
            shutil.copy2(_SETTINGS_FILE, _SETTINGS_FILE + ".corrupt")
        except Exception as _ignored_exc:
            logger.debug("Ignored recoverable exception in _load_settings (line 1582): %s", _ignored_exc)
    return dict(_SETTINGS_DEFAULTS)

def _save_settings(settings: Dict[str, Any]) -> None:
    try:
        os.makedirs(os.path.dirname(_SETTINGS_FILE), exist_ok=True)
        # v7.5.6 fix: atomic write (tmp + os.replace), same pattern already
        # used by _save_history / save_resume_state. A crash mid-write used
        # to leave a truncated settings.json that _load_settings silently
        # replaced with defaults.
        tmp = _SETTINGS_FILE + ".tmp"
        with open(tmp, "w", encoding="utf-8") as f:
            json.dump(settings, f, indent=2, ensure_ascii=False)
        os.replace(tmp, _SETTINGS_FILE)
    except Exception as e:
        logger.warning(f"Could not save settings: {e}")


# v7.5.8 Item 7: settings read-modify-write race fix.
# Many call sites do `s = _load_settings(); s[k] = v; _save_settings(s)` from
# different threads (GUI toggles, network setters, panels). With no lock, two
# concurrent RMW cycles could lose one update (last-write-wins drops a key).
# The atomic write prevented corruption but not lost updates. _update_setting()
# serializes the whole load→modify→save cycle so no update is dropped.
_SETTINGS_LOCK = threading.Lock()


def _update_setting(key: str, value: Any) -> None:
    """Thread-safe single-key update that never drops a concurrent change."""
    with _SETTINGS_LOCK:
        s = _load_settings()
        s[key] = value
        _save_settings(s)


def _update_settings(updates: Dict[str, Any]) -> None:
    """Thread-safe multi-key update under one lock acquisition."""
    with _SETTINGS_LOCK:
        s = _load_settings()
        s.update(updates)
        _save_settings(s)


# ── v1.0.1 stabilization: GUI theme + dependency diagnostics helpers ─────────────
_THEME_MODE_CANONICAL = {
    "dark": "Dark",
    "light": "Light",
    "system": "System",
}


def _normalize_theme_mode(value: Any) -> str:
    """Return a CTk-compatible theme mode; unknown values fall back to System."""
    mode = _THEME_MODE_CANONICAL.get(str(value or "").strip().lower())
    return mode or "System"


def _normalize_accent_color(value: Any, fallback: str = "#3b82f6") -> str:
    """Accept only #RRGGBB accent colors; ignore unsafe/invalid values."""
    text = str(value or "").strip()
    if re.fullmatch(r"#[0-9a-fA-F]{6}", text):
        return text.lower()
    return fallback


def _system_prefers_dark() -> bool:
    """Best-effort OS theme probe used only when GUI theme is set to System."""
    try:
        import platform as _platform
        system = _platform.system().lower()
        if system == "windows":
            try:
                import winreg  # type: ignore
                key = winreg.OpenKey(
                    winreg.HKEY_CURRENT_USER,
                    r"Software\Microsoft\Windows\CurrentVersion\Themes\Personalize",
                )
                value, _ = winreg.QueryValueEx(key, "AppsUseLightTheme")
                return int(value) == 0
            except Exception:
                return True
        if system == "darwin":
            try:
                import subprocess as _sp
                r = _sp.run(
                    ["defaults", "read", "-g", "AppleInterfaceStyle"],
                    stdout=_sp.PIPE, stderr=_sp.DEVNULL, timeout=2, text=True,
                )
                return "dark" in (r.stdout or "").lower()
            except Exception:
                return True
        env_theme = (
            os.environ.get("GTK_THEME")
            or os.environ.get("XDG_CURRENT_DESKTOP")
            or os.environ.get("COLORFGBG")
            or ""
        ).lower()
        if "light" in env_theme:
            return False
        if "dark" in env_theme:
            return True
    except Exception:
        pass
    return True


def _resolve_theme_is_dark(mode: Any) -> bool:
    normalized = _normalize_theme_mode(mode)
    if normalized == "Light":
        return False
    if normalized == "System":
        return _system_prefers_dark()
    return True


def _detect_ffmpeg_path() -> Optional[str]:
    """Return ffmpeg executable path if available on PATH; never raises."""
    try:
        return shutil.which("ffmpeg")
    except Exception:
        return None


def _ffmpeg_install_guide() -> str:
    return (
        "FFMPEG install guide:\n"
        "  Windows : winget install Gyan.FFmpeg  OR  choco install ffmpeg; then reopen Terminal.\n"
        "  Linux   : sudo apt install ffmpeg  OR  sudo dnf install ffmpeg  OR  sudo pacman -S ffmpeg.\n"
        "  macOS   : brew install ffmpeg.\n"
        "  Verify  : ffmpeg -version\n"
        "  Note    : Missing ffmpeg only disables/limits media conversion features that need it; normal JSON/asset downloads continue."
    )


# ── v1.0 Release Feature #1: settings export / import ─────────────────────────────
# Schema version is bumped only when the settings shape changes in a way that
# importers must know about. Export/import are additive and never touch the
# download pipeline or output formats.
_SETTINGS_SCHEMA_VERSION = 1

# Keys that must NEVER leave the machine in an export. Anything matching an
# exact name OR any of the substring fragments below is dropped (denylist, not
# allowlist, so future secret-ish keys are caught by fragment too).
_SETTINGS_SECRET_KEYS = {
    "ai_api_key",
    "ai_api_key_anthropic",
    "ai_api_key_openai",
    "ai_api_key_gemini",
    "ai_api_key_deepseek",
    "ai_api_key_qwen",
    "ai_api_key_groq",
    "ai_api_key_openrouter",
    "ai_api_key_custom",
    "itch_api_key",
}
_SETTINGS_SECRET_FRAGMENTS = (
    "api_key", "apikey", "token", "password", "passwd", "secret",
    "cookie", "auth", "credential", "bearer",
)
_REDACTED_PLACEHOLDER = "__REDACTED__"


def _is_secret_setting_key(key: str) -> bool:
    k = str(key).lower()
    if key in _SETTINGS_SECRET_KEYS:
        return True
    return any(frag in k for frag in _SETTINGS_SECRET_FRAGMENTS)


def export_settings(path: str) -> Tuple[bool, str]:
    """Write a redacted settings.json copy. Secrets are dropped, not masked-in.

    Returns (ok, message). Never raises. Never writes a secret value. A
    placeholder is recorded under "_redacted" purely as an informational list
    of which keys were withheld; their values are not included.
    """
    try:
        with _SETTINGS_LOCK:
            current = _load_settings()
        safe: Dict[str, Any] = {}
        redacted = []
        for k, v in current.items():
            if _is_secret_setting_key(k):
                redacted.append(k)
                continue
            safe[k] = v
        payload = {
            "_meta": {
                "app_version": _APP_VERSION,
                "schema_version": _SETTINGS_SCHEMA_VERSION,
                "exported_at": datetime.now(timezone.utc).strftime("%Y-%m-%dT%H:%M:%SZ"),
                "redacted_keys": sorted(redacted),
            },
            "settings": safe,
        }
        os.makedirs(os.path.dirname(os.path.abspath(path)) or ".", exist_ok=True)
        tmp = path + ".tmp"
        with open(tmp, "w", encoding="utf-8") as f:
            json.dump(payload, f, indent=2, ensure_ascii=False)
        os.replace(tmp, path)
        return True, (f"Settings exported to {path} "
                      f"({len(safe)} keys, {len(redacted)} secret keys withheld).")
    except Exception as e:
        return False, f"Settings export failed: {e}"


def import_settings(path: str) -> Tuple[bool, str]:
    """Merge a settings export back in, validating and ignoring secrets.

    Rules:
      • file must be valid JSON in the export envelope (or a bare settings dict
        for tolerance with hand-written files);
      • only keys already known in _SETTINGS_DEFAULTS are merged, unless nested
        under a safe "extra" dict (stored verbatim, never executed);
      • values are type-checked against the default's type where the default is
        a bool/int/str (best-effort; mismatches are skipped, not coerced);
      • a redacted placeholder value is ignored so a secret is never restored
        from a redacted marker;
      • secret-named keys are never imported even if present with a real value.
    Import MERGES (existing unspecified keys are preserved). Never raises.
    """
    try:
        if not os.path.exists(path):
            return False, f"Import failed: file not found: {path}"
        with open(path, encoding="utf-8") as f:
            raw = json.load(f)
    except json.JSONDecodeError as e:
        return False, f"Import failed: invalid JSON ({e})."
    except Exception as e:
        return False, f"Import failed: {e}"

    if isinstance(raw, dict) and isinstance(raw.get("settings"), dict):
        incoming = raw["settings"]
    elif isinstance(raw, dict):
        incoming = raw  # tolerate a bare settings dict
    else:
        return False, "Import failed: unexpected JSON structure (expected an object)."

    accepted: Dict[str, Any] = {}
    skipped_secret = 0
    skipped_unknown = 0
    skipped_type = 0
    skipped_redacted = 0
    extra_in = incoming.get("extra") if isinstance(incoming.get("extra"), dict) else None

    for k, v in incoming.items():
        if k == "extra":
            continue
        if v == _REDACTED_PLACEHOLDER:
            skipped_redacted += 1
            continue
        if _is_secret_setting_key(k):
            skipped_secret += 1
            continue
        if k not in _SETTINGS_DEFAULTS:
            skipped_unknown += 1
            continue
        default_v = _SETTINGS_DEFAULTS[k]
        # Best-effort type check only for concrete scalar defaults.
        if isinstance(default_v, bool):
            if not isinstance(v, bool):
                skipped_type += 1
                continue
        elif isinstance(default_v, int) and not isinstance(default_v, bool):
            if not isinstance(v, int) or isinstance(v, bool):
                skipped_type += 1
                continue
        elif isinstance(default_v, str):
            if not isinstance(v, str):
                skipped_type += 1
                continue
        accepted[k] = v

    if extra_in:
        # Stored verbatim under a namespaced key; never code, never secrets.
        clean_extra = {ek: ev for ek, ev in extra_in.items()
                       if not _is_secret_setting_key(ek) and ev != _REDACTED_PLACEHOLDER}
        if clean_extra:
            accepted["extra"] = clean_extra

    if not accepted:
        return False, ("Import found no safe, known settings to apply "
                       f"(secret={skipped_secret}, unknown={skipped_unknown}, "
                       f"type-mismatch={skipped_type}, redacted={skipped_redacted}).")

    _update_settings(accepted)
    return True, (f"Imported {len(accepted)} settings (merged). Skipped: "
                  f"{skipped_secret} secret, {skipped_unknown} unknown, "
                  f"{skipped_type} type-mismatch, {skipped_redacted} redacted.")


