        self._ai_enabled  = _ai_settings.get("ai_enabled", False)
        self._ai_model    = _get_ai_model(self._ai_provider)
        self._ai_mode     = _normalize_ai_mode(_ai_settings.get("ai_mode", "auto_fallback"))
        self._mode_var    = "auto"
