        key_entry = ctk.CTkEntry(key_card, show="•", placeholder_text=("leave blank for public assets" if is_en else "kosongkan untuk aset publik"), height=32, fg_color=p["input_bg"], text_color=p["input_fg"], border_color=p["border"])
