        hint = ctk.CTkLabel(
            win,
            text=lbl["hint"],
            font=ctk.CTkFont("Segoe UI", 10),
            text_color=p["muted"],
            anchor="w",
        )
        hint.pack(fill="x", padx=14, pady=(8, 6))

        summary_row = ctk.CTkFrame(win, fg_color="transparent")
